#if defined(ENABLE_DP)
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#if defined(ENABLE_HP)
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

__kernel void benchmark_func(const class_T seed, __global class_T* data) {
  const size_t gid = get_global_id(0);
  const size_t gsize = get_global_size(0);

#ifdef BLOCK_STRIDED
  const size_t lid = get_local_id(0);
  const size_t group_id = get_group_id(0);
  const size_t base = group_id * ((size_t)blockdim * (size_t)ELEMENTS_PER_THREAD * (size_t)FUSION_DEGREE) + lid;
  const size_t stride = (size_t)blockdim;
#else
  const size_t base = gid;
  const size_t stride = gsize;
#endif

  for (uint f = 0; f < (uint)FUSION_DEGREE; ++f) {
    const size_t fusion_base = base + (size_t)f * (size_t)ELEMENTS_PER_THREAD * stride;

    for (uint e = 0; e < (uint)ELEMENTS_PER_THREAD; ++e) {
      const size_t idx = fusion_base + (size_t)e * stride;
      class_T t = data[idx];

      for (uint j = 0; j < (uint)COMPUTE_ITERATIONS; ++j) {
        t = t * t + seed;
      }

      data[idx] = t;
    }
  }
}
